import org.owasp.encoder.Encode;

import java.util.Scanner;

public class SecureXSSExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Properly escaping user input before including it in the HTML response
        String encodedName = Encode.forHtml(name);
        String htmlResponse = "<h1>Welcome, " + encodedName + "!</h1>";

        System.out.println(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
